-- IDEA 19: Auto-post Social Media Scheduler (cancelled) - Author 4
-- ============================================================
INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(19, 4, E'# PostClock - Social Media Scheduler Built for Small Business Owners, Not Social Media Managers\n\n## 1. Executive Summary\n\nPostClock is a simplified social media scheduling tool designed for small business owners who manage their own social media without dedicated marketing staff. Unlike Buffer or Hootsuite — built for agencies and marketing teams — PostClock is built for the plumber who wants to post before-and-after photos, the bakery owner who wants to announce daily specials, and the yoga studio that needs to promote weekend classes without spending 2 hours on it.\n\n**Core Insight**: 71% of small business owners manage their own social media, but only 22% use a scheduling tool. The gap is not awareness — it''s that existing tools feel overwhelming to non-marketers. PostClock closes this with a "15 minutes per week" promise.\n\n**Target**: Small business owners (1-10 employees) in service and retail sectors managing their own social media presence across Instagram, Facebook, and Google Business Profile.\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| US small businesses (1-10 employees) | ~6 million | SBA 2023 |\n| % managing own social media | ~71% | Clutch survey |\n| % using a scheduling tool | ~22% | Hootsuite survey |\n| Avg time spent on social media/week | 6.1 hours | Clutch |\n| Avg posting frequency (without tools) | 2.3x/week | Sprout Social |\n| Optimal posting frequency (with tools) | 5-7x/week | Platform recommendations |\n| Social media software TAM (SMB) | ~$2.4B/yr | Market research |\n| Target SAM (underserved non-marketer owners) | ~$480M/yr | 20% of TAM |\n\n**Key Insight**: The businesses most hurt by inconsistent posting (restaurants, salons, fitness studios, retail) are the same ones whose owners have the least time to post consistently. A tool that reduces posting time from 6 hrs/week to 1 hr/week has enormous perceived value.\n\n## 3. Competitive Landscape\n\n| Tool | Target User | Price/mo | Core Weakness |\n|------|-------------|---------|---------------|\n| Buffer | Marketing teams | $6-$120 | Designed for teams, intimidating for solo owners |\n| Hootsuite | Agencies | $49-$249 | Complex, expensive, feature-heavy |\n| Later | Instagram-focused | $18-$80 | Instagram-first, other platforms secondary |\n| Metricool | Mixed | $22-$139 | Analytics-heavy, too complex for non-marketers |\n| Facebook Business Suite | Facebook/IG only | Free | Limited to Meta platforms, no scheduling for Google |\n| **PostClock** | **Non-marketer owners** | **$19-$49** | **New entrant, smaller brand** |\n\n## 4. Target User Personas\n\n### Persona A: Kevin - The HVAC Contractor\n- **Age**: 42, male, suburban Texas\n- **Business**: 7-employee HVAC company, $1.2M revenue\n- **Social media situation**: Posts randomly when he remembers (1-2x/month), mostly job site photos from his phone\n- **Core pain**: Knows he should post more but has no system; posts feel like homework\n- **What he wants**: Something that lets him dump 10 photos on Sunday and automatically post them throughout the week\n- **Tech comfort**: Moderate; uses QuickBooks, schedules via phone calendar\n- **Willingness to pay**: $19-$29/month if it takes less than 30 minutes/week\n\n### Persona B: Amy - The Boutique Fitness Studio Owner\n- **Age**: 36, female, Nashville TN\n- **Business**: Yoga + pilates studio, 3 instructors, 180 members\n- **Social media situation**: Posts class schedules and motivational content but burns out; hired a virtual assistant who made it worse\n- **Core pain**: Content creation is the hard part — she knows what to say but hates creating graphics\n- **What she wants**: Built-in content templates for fitness studios that she can customize in minutes\n- **Willingness to pay**: $29-$39/month with templates included\n\n### Persona C: Sandra - The Independent Jeweler\n- **Age**: 51, female, Philadelphia PA\n- **Business**: Custom jewelry boutique, solo operation\n- **Social media situation**: Instagram is her primary sales channel; 3,200 followers; posts inconsistently when she has new pieces\n- **Core pain**: When she goes 2 weeks without posting, she loses 30-40% of her engagement\n- **What she wants**: A queue system that lets her batch-load content so she always has posts going out even during busy production weeks\n- **Willingness to pay**: $29-$49/month, values Instagram-specific features\n\n## 5. Core Features\n\n| Priority | Feature | Description |\n|----------|---------|-------------|\n| P0 | Post composer | Write caption, upload photo/video, pick date/time, pick platforms |\n| P0 | Content queue | Set weekly posting cadence; posts auto-fill from queue |\n| P0 | Platform connections | Instagram Business, Facebook Page, Google Business Profile |\n| P0 | Mobile-first interface | Compose and schedule from phone in under 2 minutes |\n| P0 | Calendar view | See all scheduled posts in one monthly view |\n| P1 | Caption templates | Industry-specific starter captions (fitness, food, retail, home services) |\n| P1 | Best time suggestions | Recommend posting times based on historical engagement |\n| P1 | First comment scheduling | Auto-post hashtags as first comment (Instagram strategy) |\n| P1 | Repost / content recycler | Re-queue evergreen posts after 90 days automatically |\n| P2 | Basic analytics | Reach, engagement, follower growth per post |\n| P2 | Canva integration | Design in Canva, publish in PostClock |\n| P2 | AI caption generator | Input photo description → suggested caption with emoji and hashtags |\n\n## 6. Technical Architecture\n\n```\nFrontend:\n  - Web app: Next.js 15 + TailwindCSS (mobile-first responsive)\n  - Mobile PWA: Installable on iOS/Android homescreen\n\nBackend:\n  - Go + Echo v4\n  - Platform APIs:\n    - Instagram Graph API (Business accounts)\n    - Facebook Graph API (Pages)\n    - Google Business Profile API (posts)\n  - Job queue: Redis + background workers for scheduled post dispatch\n  - Media storage: Cloudflare R2 (images/videos until post time)\n\nData:\n  - PostgreSQL 16 (posts, schedules, platform connections, users)\n  - Redis (job queue, rate limiting)\n\nAuth:\n  - Email/password\n  - OAuth for each platform connection (Instagram, Facebook, Google)\n\nInfrastructure:\n  - Backend: Fly.io\n  - Frontend: Vercel\n```\n\n**API Complexity Note**: Instagram''s Graph API requires a Facebook Business account and has strict rate limits. This is the highest technical risk in the MVP and requires dedicated API integration work and fallback handling.\n\n## 7. Business Model\n\n| Plan | Price | Social Profiles | Posts/Month | Key Features |\n|------|-------|----------------|-------------|-------------|\n| Solo | $19/mo | 3 platforms | 30 | Core scheduling, calendar, queue |\n| Growth | $35/mo | 6 platforms | 100 | + Templates, best times, recycler |\n| Pro | $49/mo | 10 platforms | Unlimited | + Analytics, AI captions, Canva |\n\n**Revenue projection**:\n- Month 6: 300 paid users avg $32/mo = $9,600 MRR\n- Month 12: 900 paid users avg $35/mo = $31,500 MRR\n\n## 8. MVP Roadmap\n\n| Phase | Duration | Deliverables | Gate |\n|-------|----------|-------------|------|\n| M1: Core scheduler | 6 weeks | Composer, queue, Instagram + Facebook | 20 beta users posting weekly |\n| M2: Google + mobile | 3 weeks | Google Business Profile, PWA, calendar | Mobile usage >50% |\n| M3: Templates + retention | 4 weeks | Caption templates, best times, recycler | 30-day retention >55% |\n| M4: Monetize + grow | 3 weeks | Billing, analytics, referral | 80 paying users |\n\n## 9. Success Metrics\n\n| KPI | 6-Month Target |\n|-----|----------------|\n| Registered users | 800 |\n| Paid subscribers | 280 |\n| MRR | $9,000 |\n| Avg posts scheduled/user/week | ≥4 |\n| 30-day retention | ≥55% |\n| Mobile session rate | ≥60% |\n| NPS | ≥45 |\n\n## 10. Risks & Mitigation\n\n| Risk | Severity | Probability | Mitigation |\n|------|----------|-------------|------------|\n| Instagram API policy changes (has happened before) | High | Medium | Build Facebook first; Instagram shares Graph API but FB is more stable |\n| Users sign up but don''t connect social accounts | High | High | Onboarding wizard forces platform connection as step 1 |\n| Content creation (not scheduling) is the real barrier | Medium | High | Add AI caption generator and templates early (P1, not P2) |\n| Crowded market perception | Medium | High | Marketing focuses on "15 minutes per week" promise, not feature comparison |\n| Platform rate limits causing delayed posts | Medium | Medium | Buffer queue with retry logic; notify user if post delayed >15 min |',
    E'[{"step":"Market positioning","decision":"Target non-marketer small business owners, not marketing teams","reason":"Buffer and Hootsuite own the agency/team market; the 71% of small business owners managing their own social are underserved and have different needs"},{"step":"Core UX promise","decision":"15 minutes per week as the product headline","reason":"Feature lists don''t motivate busy owners; a time promise does - it reframes the product from software to time savings"},{"step":"Platform priority","decision":"Instagram + Facebook first, Google Business Profile second","reason":"Meta platforms cover 90% of small business social activity; Google Business posts are underused but high-value for local SEO"},{"step":"Template strategy","decision":"Industry-specific templates in P1, not P2","reason":"Content creation is the actual blocker for most owners (not scheduling); solving it in first iteration dramatically improves activation and retention"},{"step":"Pricing","decision":"$19 entry tier","reason":"Must be below $20/month to compete with the mental model of free tools (Facebook Business Suite); $19 is under the impulse-purchase threshold for most small business owners"},{"step":"PWA over native app","decision":"Mobile PWA instead of native iOS/Android","reason":"App store submission delays are 2-4 weeks; PWA delivers 90% of the mobile experience with zero app store dependency; business owners primarily post from their phones"}]',
    'submitted', 28, NOW() - INTERVAL '23 days', NOW() - INTERVAL '24 days', NOW() - INTERVAL '23 days'),

