INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(20, 7, E'# RxExpiry - Medication Expiry Tracking & Compliance for Independent Pharmacies\n\n## 1. Executive Summary\n\nRxExpiry is a dedicated inventory expiry management system for independent pharmacies managing 2,000-5,000 SKUs. The product replaces manual shelf-checking routines with a barcode-scan workflow that logs expiry dates, auto-generates 60/30/7 day alerts, and produces regulatory-compliant disposal documentation. For independent pharmacy owners, expired medication on the shelf is both a patient safety risk and a regulatory liability — RxExpiry eliminates this risk systematically.\n\n**Target Problem**: Independent pharmacies lose an average of $15,000-$45,000 per year to expired stock write-offs, and face potential $10,000+ fines per inspection violation for undiscovered expired medications on the shelf.\n\n**Value Proposition**: Never be surprised by an expired shelf item again. Pass every inspection. Reduce write-off losses by 60%.\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| Independent pharmacies in US | ~22,000 | NCPA 2023 |\n| Avg SKUs per independent pharmacy | 2,000-5,000 | NCPA survey |\n| Avg annual expired drug write-off loss | $18,000 | Pharmacy Times |\n| % using dedicated expiry tracking software | <12% | Industry estimate |\n| Typical manual expiry check frequency | Monthly | NABP guidance |\n| FDA inspection fine range (expired meds) | $1,000-$50,000 | FDA enforcement data |\n| State board inspection frequency | 1-3x per year | Average across states |\n| Software TAM (independent pharmacy mgmt) | ~$110M/yr | 22k × ~$5,000/yr avg |\n\n**Regulatory pressure increasing**: Multiple states have strengthened expired medication inspection requirements since 2022, increasing the compliance burden on independent pharmacies that lack the IT infrastructure of chain pharmacies.\n\n## 3. Competitive Landscape\n\n| Product | Type | Price/mo | Expiry-Specific? | Independent-Focused? |\n|---------|------|----------|-----------------|---------------------|\n| PioneerRx | Full pharmacy mgmt | $500-$900 | Partial | Partially |\n| Liberty Software | Pharmacy mgmt | $300-$700 | Partial | Yes |\n| QS/1 | Legacy PMS | $400-$800 | Partial (manual) | Partially |\n| Sorted (UK) | Expiry tracking | £49-£129 | Yes | Yes (UK only) |\n| Manual spreadsheet | DIY | $0 | User-dependent | N/A |\n| **RxExpiry** | **Expiry-native** | **$99-$199** | **Yes (core product)** | **Yes** |\n\n**Key Gap**: Existing pharmacy management systems (PMS) include expiry tracking as a minor feature within a $500-$900/month suite. RxExpiry offers best-in-class expiry tracking at one-fifth the price as a standalone add-on that integrates with existing PMS.\n\n## 4. Target User Personas\n\n### Persona A: Bob - The Owner-Pharmacist Running Tight Margins\n- **Age**: 56, male, rural Ohio\n- **Pharmacy**: 22 years in business, 3,200 SKUs, 2 part-time pharmacy technicians\n- **Current process**: Monthly manual shelf check, technicians use a paper log, Bob reviews it\n- **Pain points**:\n  1. Manual checks take 8+ hours/month of technician time\n  2. Caught expired items 3 days before a state board inspection last year — "scared the life out of me"\n  3. Waste from short-dated items that could have been returned is untracked\n- **What he wants**: An alert system that finds items before they expire, generates the paperwork automatically\n- **Tech comfort**: Moderate; uses computer PMS, familiar with barcode scanners\n- **Willingness to pay**: $99-$149/month if it reduces inspection anxiety\n\n### Persona B: Rachel - The High-Volume Community Pharmacy Manager\n- **Age**: 41, female, suburban New Jersey\n- **Pharmacy**: 4,800 SKUs, high over-the-counter turnover, 1 full-time tech\n- **Pain points**:\n  1. OTC products rotate fast but specialty medications sit; hard to track both\n  2. Has had 2 items flagged by state inspectors in 3 years ($3,800 in fines)\n  3. Wants to move to scan-at-receiving to log expiry dates at intake, not retroactively\n- **Specific need**: Scan-at-receiving workflow to log expiry at intake; compliance report export\n- **Willingness to pay**: $149-$199/month if it integrates with her Cardinal Health ordering system\n\n### Persona C: James - The Cost-Conscious New Pharmacy Owner\n- **Age**: 34, male, recently bought independent pharmacy\n- **Pharmacy**: 2,100 SKUs, inherited outdated manual system\n- **Pain**: Taking over from retiring owner who did everything manually; wants to modernize quickly\n- **Budget concern**: Can''t afford a full PMS switch; needs targeted solutions\n- **Need**: Standalone expiry tracker that doesn''t require replacing his entire system\n- **Willingness to pay**: $99/month as a standalone tool\n\n## 5. Core Features\n\n| Priority | Feature | Description |\n|----------|---------|-------------|\n| P0 | Barcode scan inventory intake | Scan NDC barcode, enter expiry date; item logged to database |\n| P0 | Expiry calendar view | Visual month-view of all items expiring within 90 days |\n| P0 | 60/30/7 day automated alerts | Email + in-app alerts as expiry windows approach |\n| P0 | Expired item log | Record of all expired items removed from shelf with timestamps |\n| P0 | Disposal report export | PDF report formatted for state board compliance documentation |\n| P1 | Scan-at-receiving mode | Scan items as they arrive from distributor; auto-log expiry |\n| P1 | Return-to-vendor tracking | Log items returned before expiry for credit; track credit recovery |\n| P1 | Bulk CSV import | Import existing inventory from PMS export |\n| P1 | Multi-user (tech accounts) | Technicians can scan and log; pharmacist reviews and approves |\n| P2 | Expiry trend analytics | Which drug categories expire most; seasonal patterns |\n| P2 | DEA Schedule II separate tracking | Separate workflow for controlled substance expiry per DEA requirements |\n| P2 | Distributor integration (Cardinal, McKesson) | Auto-import expiry data from order invoices |\n\n## 6. Technical Architecture\n\n```\nSystem Overview:\n\nFrontend:\n  - Pharmacist dashboard: Next.js 15 + TailwindCSS\n  - Tablet-optimized for barcode scanning workflow at the counter\n  - Technician mobile view: Simplified scan interface\n\nBackend:\n  - Go + Echo v4\n  - Barcode lookup: NDC database API (OpenFDA NDC API, free)\n    - Auto-populate drug name, manufacturer from NDC scan\n  - Cron jobs: Daily expiry check, alert dispatch\n  - PDF generation: Puppeteer (disposal reports)\n\nData:\n  - PostgreSQL 16 (inventory items, expiry records, alerts, disposal logs)\n  - Redis (session, cron coordination)\n\nBarcode Integration:\n  - Web Serial API for USB barcode scanners\n  - Camera-based scanning: @zxing/library (mobile browser)\n\nNotifications:\n  - SendGrid (daily expiry digest, threshold alerts)\n  - Optional SMS (Twilio) for critical expiry alerts\n\nSecurity:\n  - HIPAA considerations: PHI not stored (inventory only, no patient data)\n  - Data encryption at rest (AES-256)\n  - Role-based access: Owner, Pharmacist, Technician\n```\n\n**HIPAA Note**: RxExpiry handles drug inventory data only — no patient prescription data. This eliminates HIPAA covered entity concerns, significantly simplifying compliance requirements.\n\n## 7. Business Model\n\n| Plan | Price/mo | SKU Limit | Key Features |\n|------|----------|-----------|-------------|\n| Basic | $99/mo | 2,500 SKUs | Scan intake, expiry alerts, disposal reports |\n| Professional | $149/mo | 5,000 SKUs | + Scan-at-receiving, return tracking, multi-user |\n| Enterprise | $199/mo | Unlimited | + Analytics, DEA Schedule II, distributor integration |\n| Annual discount | 2 months free | All plans | Billed annually |\n\n**Why standalone works**: Pharmacies pay $500-$900/month for PMS but expiry tracking inside those systems is poor. A $99-$199 add-on with superior expiry workflow has an easy ROI story: one avoided fine pays for 3+ years of subscription.\n\n## 8. MVP Roadmap\n\n| Phase | Duration | Deliverables | Gate |\n|-------|----------|-------------|------|\n| M1: Core scanning | 6 weeks | Barcode scan intake, expiry calendar, 60/30/7 alerts | 6 beta pharmacies |\n| M2: Compliance | 3 weeks | Disposal report PDF, expired item log, CSV import | Compliance report passes state board review |\n| M3: Workflow | 4 weeks | Scan-at-receiving, multi-user accounts, return tracking | Technicians using without training |\n| M4: Growth | 3 weeks | Billing, analytics, NCPA partnership outreach | 30 paying pharmacies |\n\n## 9. Success Metrics\n\n| KPI | 3-Month Target | 6-Month Target |\n|-----|---------------|----------------|\n| Registered pharmacies | 50 | 150 |\n| Paid subscribers | 25 | 80 |\n| MRR | $2,800 | $11,000 |\n| Avg SKUs tracked per pharmacy | 2,400 | 2,800 |\n| Items caught before expiry (vs. manual baseline) | 3x | 5x |\n| Inspection pass rate (self-reported) | 100% | 100% |\n| Pharmacist NPS | ≥52 | ≥60 |\n\n## 10. Risks & Mitigation\n\n| Risk | Severity | Probability | Mitigation |\n|------|----------|-------------|------------|\n| PMS vendors bundle better expiry tracking to compete | High | Medium | Focus on superior UX and standalone pricing; PMS can''t easily reorient their entire product |\n| Pharmacy owners skeptical of cloud storage for drug data | High | High | Emphasize no patient data stored; offer data export any time; SOC 2 roadmap transparency |\n| NDC database coverage gaps for specialty drugs | Medium | Medium | Fallback to manual drug name entry; submit gaps to OpenFDA |\n| Hardware scanner compatibility issues | Medium | Medium | Test with top 5 USB barcode scanner models; document compatibility list |\n| Low adoption speed (pharmacy owners are risk-averse) | High | High | NCPA (National Community Pharmacists Association) partnership for trust transfer |',
    E'[{"step":"Product scope","decision":"Standalone expiry tracker, not full pharmacy management system","reason":"Full PMS costs $500-$900/month and takes months to implement; a focused $99-$199/month expiry tool solves the #1 compliance pain point with zero switching cost"},{"step":"HIPAA scope","decision":"Inventory data only, no patient prescription data","reason":"This single architectural decision eliminates HIPAA covered entity complexity, speeds to market by 6+ months, and removes the primary trust barrier for pharmacy owners"},{"step":"Barcode approach","decision":"Web Serial API for USB scanners + camera fallback","reason":"Most pharmacies already own USB barcode scanners; supporting them avoids hardware investment barrier; camera fallback on mobile for staff scanning shelf items"},{"step":"Compliance report","decision":"PDF disposal report formatted to state board requirements as P0","reason":"This feature is the primary ROI justification; pharmacists will pay for inspection anxiety reduction before any other feature"},{"step":"Pricing","decision":"$99/$149/$199 with SKU-based limits","reason":"Limits align with the natural pharmacy size tiers (small/medium/large independent); allows upsell as pharmacy grows inventory"},{"step":"Go-to-market","decision":"NCPA (National Community Pharmacists Association) partnership as primary channel","reason":"Pharmacy owners trust NCPA endorsements over software ads; a single featured article in America''s Pharmacist magazine reaches more decision-makers than months of digital marketing"}]',
    'submitted', 35, NOW() - INTERVAL '25 days', NOW() - INTERVAL '26 days', NOW() - INTERVAL '25 days'),

